    SELECT 'APORTES' TIPO, '0049' COD, 'EMPRESAS FONAFE_SEGURO VIDA' DESCN, 'SEGURO VIDA' DET, '21/05/2025' FTXT, TO_DATE('21/05/2025','DD/MM/YYYY') FDATE, 'NO' IMP, 'Otros permanentes' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '5000' COD, 'GL_ESSALUD' DESCN, 'GL APORTE DEL EMPLEADOR A ESSALUD' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Essalud' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '5001' COD, 'GL_SCTR' DESCN, 'GL APORTE SCTR' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Otros permanentes' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '5002' COD, 'GL_ESSALUD OCASIONAL' DESCN, 'GL APORTE DEL EMPLEADOR A ESSALUD PARA CONCEPTO OCASIONAL' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Essalud' DTC, 'Ocasional' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '6000' COD, 'GL_ESSALUD' DESCN, 'GL APORTE DEL EMPLEADOR A ESSALUD' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Essalud' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '6001' COD, 'GL_SCTR' DESCN, 'GL APORTE SCTR' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Otros permanentes' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '6002' COD, 'GL_ESSALUD OCASIONAL' DESCN, 'GL APORTE DEL EMPLEADOR A ESSALUD PARA CONCEPTO OCASIONAL' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Essalud' DTC, 'Ocasional' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '7000' COD, 'GL_ESSALUD' DESCN, 'GL APORTE DEL EMPLEADOR A ESSALUD' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Essalud' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '7001' COD, 'GL_SCTR' DESCN, 'GL APORTE SCTR' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Otros permanentes' DTC, 'Permanente' TN, 'Activo' EST, 'S' SEL FROM DUAL UNION ALL
    SELECT 'APORTES' TIPO, '7002' COD, 'GL_ESSALUD OCASIONAL' DESCN, 'GL APORTE DEL EMPLEADOR A ESSALUD PARA CONCEPTO OCASIONAL' DET, '01/03/2024' FTXT, TO_DATE('01/03/2024','DD/MM/YYYY') FDATE, 'NO' IMP, 'Essalud' DTC, 'Ocasional' TN, 'Activo' EST, 'S' SEL FROM DUAL
) s
ON (d.TIPO = s.TIPO AND d.CODIGO_CONCEPTO_MGRH = s.COD AND d.ANIO_CATALOGO = 2026)
WHEN MATCHED THEN UPDATE SET
    d.DESCRIPCION_NORMA=s.DESCN, d.DETALLE_NORMA=s.DET, d.FECHA_VIGENCIA_TEXTO=s.FTXT,
    d.FECHA_VIGENCIA_DATE=s.FDATE, d.IMPONIBLE=s.IMP, d.DESCRIPCION_TIPO_CONCEPTO=s.DTC,
    d.TIPO_NORMA=s.TN, d.ESTADO=s.EST, d.SELECCIONABLE=s.SEL, d.FECHA_MODIFICACION=SYSDATE
WHEN NOT MATCHED THEN INSERT
    (TIPO, CODIGO_CONCEPTO_MGRH, DESCRIPCION_NORMA, DETALLE_NORMA, FECHA_VIGENCIA_TEXTO,
     FECHA_VIGENCIA_DATE, IMPONIBLE, DESCRIPCION_TIPO_CONCEPTO, TIPO_NORMA, ESTADO,
     SELECCIONABLE, ANIO_CATALOGO, VIGENTE, FUENTE_CATALOGO, ACTIVO, FECHA_REGISTRO)
    VALUES (s.TIPO, s.COD, s.DESCN, s.DET, s.FTXT, s.FDATE, s.IMP, s.DTC, s.TN, s.EST,
     s.SEL, 2026, 'S', 'Conceptos2026.xls', 1, SYSDATE);

COMMIT;

